# %% [markdown]
# # Fold-local preprocessing and pair-query construction

# %%
class FoldPreprocessor:
    def fit(self, X):
        assert "CENTER" not in X.columns
        assert "CYTOGENETICS" not in X.columns
        self.input_columns_ = X.columns.tolist()

        self.kept_not_all_missing_ = X.columns[~X.isna().all(axis=0)].tolist()
        if len(self.kept_not_all_missing_) == 0:
            raise ValueError("All columns are all-missing in this training fold.")

        X0 = X[self.kept_not_all_missing_].copy()
        self.imputer_ = SimpleImputer(strategy="median")
        Xi = pd.DataFrame(
            self.imputer_.fit_transform(X0),
            columns=self.kept_not_all_missing_,
            index=X.index,
        )

        self.kept_nonconstant_ = Xi.columns[Xi.nunique(dropna=False) > 1].tolist()
        if len(self.kept_nonconstant_) == 0:
            raise ValueError("No nonconstant columns remain after fold-local imputation.")
        Xi = Xi[self.kept_nonconstant_]

        self.kept_columns_ = Xi.T.drop_duplicates().T.columns.tolist()
        if len(self.kept_columns_) == 0:
            raise ValueError("No columns remain after fold-local duplicate removal.")

        self.scaler_ = StandardScaler()
        self.scaler_.fit(Xi[self.kept_columns_])
        return self

    def transform(self, X):
        assert "CENTER" not in X.columns
        assert "CYTOGENETICS" not in X.columns
        X0 = X[self.kept_not_all_missing_].copy()
        Xi = pd.DataFrame(
            self.imputer_.transform(X0),
            columns=self.kept_not_all_missing_,
            index=X.index,
        )
        Xi = Xi[self.kept_columns_]
        Xi = pd.DataFrame(
            self.scaler_.transform(Xi),
            columns=self.kept_columns_,
            index=X.index,
        )
        assert np.isfinite(Xi.to_numpy()).all()
        return Xi


def rank01(values):
    values = np.asarray(values, dtype=float)
    return pd.Series(values).rank(method="average").to_numpy(dtype=float) / (len(values) + 1.0)


def ipcw_score(y_train_fold, y_valid_fold, pred_valid, tau=TAU):
    return float(concordance_index_ipcw(y_train_fold, y_valid_fold, pred_valid, tau=tau)[0])


def fit_censoring_km(y_train_fold):
    event, time_arr = y_event_time(y_train_fold)
    censor_event = ~event
    unique_times = np.sort(np.unique(time_arr[np.isfinite(time_arr)]))
    surv_values = []
    surv = 1.0
    for t in unique_times:
        at_risk = np.sum(time_arr >= t)
        d_censor = np.sum((time_arr == t) & censor_event)
        if at_risk > 0:
            surv *= max(0.0, 1.0 - d_censor / at_risk)
        surv_values.append(surv)
    return unique_times, np.asarray(surv_values, dtype=float)


def predict_censoring_survival(km_times, km_surv, query_times):
    query_times = np.asarray(query_times, dtype=float)
    if len(km_times) == 0:
        return np.ones_like(query_times, dtype=float)
    idx = np.searchsorted(km_times, query_times, side="right") - 1
    out = np.ones_like(query_times, dtype=float)
    valid = idx >= 0
    out[valid] = km_surv[idx[valid]]
    return out


def build_pairwise_query_data(
    X_train_pp,
    y_train_fold,
    fold_seed,
    max_comparators=MAX_COMPARATORS_PER_ANCHOR,
    materialize=True,
):
    event, time_arr = y_event_time(y_train_fold)
    anchor_idx = np.flatnonzero(event & (time_arr <= TAU))
    km_times, km_surv = fit_censoring_km(y_train_fold)

    X_np = np.asarray(X_train_pp, dtype=np.float32)
    rows = []
    labels = []
    group_ids = []
    pairs = []
    pairs_weight = []
    anchor_count = 0
    skipped_no_comparator = 0
    comparator_total_before_cap = 0
    comparator_total_after_cap = 0

    for anchor_local_idx in anchor_idx:
        anchor_time = float(time_arr[anchor_local_idx])
        comparator_idx = np.flatnonzero(time_arr > anchor_time)
        if len(comparator_idx) == 0:
            skipped_no_comparator += 1
            continue

        comparator_total_before_cap += int(len(comparator_idx))
        if len(comparator_idx) > max_comparators:
            rng = np.random.default_rng(RANDOM_STATE + fold_seed * 100000 + int(anchor_local_idx))
            comparator_idx = np.sort(rng.choice(comparator_idx, size=max_comparators, replace=False))
        comparator_total_after_cap += int(len(comparator_idx))

        ghat = float(predict_censoring_survival(km_times, km_surv, [anchor_time])[0])
        anchor_weight = min(1.0 / (max(ghat, 0.05) ** 2), 25.0)
        per_pair_weight = anchor_weight / max(len(comparator_idx), 1)

        if materialize:
            group_id = anchor_count
            anchor_row_pos = len(rows)
            rows.append(X_np[anchor_local_idx])
            labels.append(1.0)
            group_ids.append(group_id)

            for comp_local_idx in comparator_idx:
                comp_row_pos = len(rows)
                rows.append(X_np[comp_local_idx])
                labels.append(0.0)
                group_ids.append(group_id)
                pairs.append([anchor_row_pos, comp_row_pos])
                pairs_weight.append(per_pair_weight)

        anchor_count += 1

    stats = {
        "anchors_total": int(len(anchor_idx)),
        "queries_built": int(anchor_count),
        "anchors_skipped_no_comparator": int(skipped_no_comparator),
        "pairs_before_cap": int(comparator_total_before_cap),
        "pairs_after_cap": int(comparator_total_after_cap),
        "max_comparators_per_anchor": int(max_comparators),
        "materialized_rows": int(len(rows)) if materialize else 0,
    }

    if not materialize:
        return None, None, None, None, None, stats
    if len(pairs) == 0:
        raise ValueError("No comparable pairs were built from this training fold.")

    return (
        np.vstack(rows).astype(np.float32),
        np.asarray(labels, dtype=np.float32),
        np.asarray(group_ids, dtype=np.int64),
        np.asarray(pairs, dtype=np.int32),
        np.asarray(pairs_weight, dtype=np.float32),
        stats,
    )


def make_group_splits(groups, n_splits=5):
    splitter = GroupKFold(n_splits=n_splits)
    return list(splitter.split(X_train_raw, y, groups=groups))


