# %% [markdown]
# # Full EXP01 diagnostic run

# %%
def common_catboost_params(config):
    return {
        "loss_function": config["loss_function"],
        "iterations": int(config["iterations"]),
        "depth": int(config["depth"]),
        "learning_rate": float(config["learning_rate"]),
        "l2_leaf_reg": float(config["l2_leaf_reg"]),
        "random_seed": RANDOM_STATE,
        "thread_count": 1,
        "allow_writing_files": False,
        "verbose": False,
        "task_type": "CPU",
    }


def score_oof_rank(oof_rank_values):
    if not np.isfinite(oof_rank_values).all():
        raise ValueError("OOF rank vector contains non-finite values.")
    return float(concordance_index_ipcw(y_full, y_full, oof_rank_values, tau=TAU)[0])


def run_catboost_candidate(config):
    if not HAS_CATBOOST:
        raise RuntimeError("CatBoost is not installed.")
    if not CATBOOST_PREFLIGHT_PASSED:
        raise RuntimeError("CatBoost preflight failed.")

    name = config["name"]
    start = time.time()
    oof_pred = np.full(len(X_train_raw), np.nan, dtype=float)
    fold_test_ranks = []
    fold_rows = []
    query_rows = []

    for fold, (tr_idx, va_idx) in enumerate(splits, start=1):
        try:
            pp = FoldPreprocessor().fit(X_train_raw.iloc[tr_idx])
            X_tr_pp = pp.transform(X_train_raw.iloc[tr_idx])
            X_va_pp = pp.transform(X_train_raw.iloc[va_idx])
            X_test_pp = pp.transform(X_test_raw)

            X_pair, label_pair, group_id, pairs, pairs_weight, stats = build_pairwise_query_data(
                X_tr_pp,
                y_full[tr_idx],
                fold_seed=fold,
                max_comparators=MAX_COMPARATORS_PER_ANCHOR,
                materialize=True,
            )

            pool = Pool(
                data=X_pair,
                label=label_pair,
                group_id=group_id,
                pairs=pairs,
                pairs_weight=pairs_weight,
            )
            model = CatBoostRanker(**common_catboost_params(config))
            model.fit(pool)

            pred_va = np.asarray(model.predict(X_va_pp), dtype=float).reshape(-1)
            pred_test = np.asarray(model.predict(X_test_pp), dtype=float).reshape(-1)
            if not np.isfinite(pred_va).all() or not np.isfinite(pred_test).all():
                raise ValueError("non-finite CatBoost predictions")

            oof_pred[va_idx] = pred_va
            fold_test_ranks.append(rank01(pred_test))
            fold_score = ipcw_score(y_full[tr_idx], y_full[va_idx], pred_va)

            fold_rows.append(
                {
                    "candidate": name,
                    "fold": fold,
                    "status": "success",
                    "ipcw_cindex": fold_score,
                    "valid_rows": int(len(va_idx)),
                }
            )
            stats.update({"candidate": name, "fold": fold, "status": "success"})
            query_rows.append(stats)
            print(f"{name} fold {fold}: IPCW={fold_score:.6f}, pairs={stats['pairs_after_cap']}")
        except Exception as exc:
            fold_rows.append(
                {
                    "candidate": name,
                    "fold": fold,
                    "status": "failed",
                    "ipcw_cindex": np.nan,
                    "valid_rows": int(len(va_idx)),
                    "message": repr(exc),
                }
            )
            query_rows.append({"candidate": name, "fold": fold, "status": "failed", "message": repr(exc)})
            print(f"Skipping {name} fold {fold}: {repr(exc)}")
            continue

    complete = np.isfinite(oof_pred).all()
    if not complete:
        raise RuntimeError(f"{name} did not produce complete OOF predictions.")

    oof_rank = rank01(oof_pred)
    test_rank = np.mean(fold_test_ranks, axis=0)
    score = score_oof_rank(oof_rank)
    elapsed_sec = time.time() - start

    score_row = {
        "candidate": name,
        "family": config["family"],
        "loss_function": config["loss_function"],
        "status": "success",
        "oof_ipcw": score,
        "elapsed_sec": elapsed_sec,
    }
    return score_row, fold_rows, query_rows, oof_pred, oof_rank, test_rank


score_rows = []
fold_rows_all = []
query_rows_all = []
oof_outputs = {}

if HAS_CATBOOST and CATBOOST_PREFLIGHT_PASSED:
    for config in EXP01_CATBOOST_CONFIGS:
        try:
            score_row, fold_rows, query_rows, oof_pred, oof_rank, test_rank = run_catboost_candidate(config)
            score_rows.append(score_row)
            fold_rows_all.extend(fold_rows)
            query_rows_all.extend(query_rows)
            name = config["name"]
            oof_outputs[f"oof_pred__{name}"] = oof_pred
            oof_outputs[f"oof_rank__{name}"] = oof_rank
            oof_outputs[f"test_rank__{name}"] = test_rank
        except Exception as exc:
            score_rows.append(
                {
                    "candidate": config["name"],
                    "family": config["family"],
                    "loss_function": config["loss_function"],
                    "status": "failed",
                    "oof_ipcw": np.nan,
                    "message": repr(exc),
                }
            )
            print(f"Candidate failed: {config['name']}: {repr(exc)}")
else:
    for config in EXP01_CATBOOST_CONFIGS:
        score_rows.append(
            {
                "candidate": config["name"],
                "family": config["family"],
                "loss_function": config["loss_function"],
                "status": "skipped_missing_or_failed_dependency",
                "oof_ipcw": np.nan,
                "message": "CatBoost missing or preflight failed.",
            }
        )

score_df = pd.DataFrame(score_rows)
fold_df = pd.DataFrame(fold_rows_all)
query_df = pd.DataFrame(query_rows_all)
score_df.to_csv(OUTPUT_DIR / "exp01_candidate_scores.csv", index=False)
fold_df.to_csv(OUTPUT_DIR / "exp01_foldwise_scores.csv", index=False)
query_df.to_csv(OUTPUT_DIR / "exp01_query_stats.csv", index=False)

successful_names = score_df.loc[score_df["status"] == "success", "candidate"].tolist()
if successful_names:
    rank_df = pd.DataFrame({name: oof_outputs[f"oof_rank__{name}"] for name in successful_names})
    rank_df.corr(method="spearman").to_csv(OUTPUT_DIR / "exp01_rank_correlation_matrix.csv")

    blend_rows = []
    reference_rank = None
    reference_message = ""
    try:
        v8 = np.load(Path("qrt_outputs_v8") / "v8cd_oof_predictions.npz")
        exp02 = np.load(Path("qrt_outputs_exp02") / "exp02_oof_test_rank_vectors.npz")
        v8e_rank = 0.42857142857142855 * rank01(v8["extra"]) + 0.5714285714285714 * rank01(v8["xgb_cox_d3_lr02"])
        reference_rank = 0.90 * rank01(v8e_rank) + 0.10 * rank01(exp02["text_only_coxnet__iscn_token_tfidf"])
        reference_score = score_oof_rank(reference_rank)
        reference_message = "current_v8e_text10_reference_reconstructed"
    except Exception as exc:
        reference_score = np.nan
        reference_message = f"reference_unavailable: {repr(exc)}"

    for name in successful_names:
        candidate_rank = oof_outputs[f"oof_rank__{name}"]
        candidate_score = score_oof_rank(candidate_rank)
        blend_rows.append(
            {
                "blend": name,
                "catboost_weight": 1.0,
                "oof_ipcw": candidate_score,
                "reference_oof_ipcw": reference_score,
                "reference_message": reference_message,
            }
        )
        if reference_rank is not None:
            for weight in [0.025, 0.05, 0.075, 0.10, 0.15]:
                blend_rank = (1.0 - weight) * rank01(reference_rank) + weight * rank01(candidate_rank)
                blend_rows.append(
                    {
                        "blend": f"current_ref_plus_{name}",
                        "catboost_weight": weight,
                        "oof_ipcw": score_oof_rank(blend_rank),
                        "reference_oof_ipcw": reference_score,
                        "reference_message": reference_message,
                    }
                )
    pd.DataFrame(blend_rows).to_csv(OUTPUT_DIR / "exp01_blend_scores.csv", index=False)
    np.savez_compressed(OUTPUT_DIR / "exp01_oof_test_rank_vectors.npz", **oof_outputs)
else:
    pd.DataFrame(
        [
            {
                "blend": "none",
                "status": "no_successful_catboost_candidates",
            }
        ]
    ).to_csv(OUTPUT_DIR / "exp01_blend_scores.csv", index=False)

no_submission_summary = pd.DataFrame(
    [
        {
            "script": "leukemia_survival_exp01_catboost_ipcw_pairrank.py",
            "mode": "full_diagnostic",
            "submission_files_generated": 0,
            "successful_candidates": int(len(successful_names)),
        }
    ]
)
no_submission_summary.to_csv(OUTPUT_DIR / "exp01_no_submission_summary.csv", index=False)
assert not list(OUTPUT_DIR.glob("submission*.csv")), "EXP01 diagnostics should not generate submission CSVs."

print("\nEXP01 candidate scores:")
display(score_df)
print("No submission files generated.")
